// mm/src/steps/uploadStep.js
import React, { useRef, useState } from 'react';
import { uploadFile } from '../api/Upload';
import { useWorkflow } from '../store/workflowContext';
import { v4 as uuidv4 } from 'uuid';

const UploadStep = () => {
  const { manuscriptFiles, addFile } = useWorkflow();
  const [progress, setProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const fileRef = useRef();

  const handleFiles = async (files) => {
    if (!files || files.length === 0) return;
    const file = files[0];

    const id = uuidv4();
    // âś… store the actual File object so Preview can read its real contents
    const meta = {
      id,
      name: file.name,
      size: file.size,
      status: 'uploading',
      progress: 0,
      file, // <--- important
    };
    addFile(meta);

    setIsUploading(true);
    try {
      const resp = await uploadFile(file, (pct) => {
        setProgress(pct);
        // In a real app youâ€™d also update this fileâ€™s progress in global state by id
      });

      // Mark as done (still keeping the File object)
      addFile({
        id,
        name: file.name,
        size: file.size,
        status: 'done',
        progress: 100,
        serverResponse: resp?.data,
        file,
      });
      setProgress(100);
    } catch (err) {
      console.error('Upload failed', err);
      addFile({
        id,
        name: file.name,
        size: file.size,
        status: 'error',
        progress: 0,
        file,
      });
    } finally {
      setIsUploading(false);
    }
  };

  const onDrop = (e) => {
    e.preventDefault();
    const dt = e.dataTransfer;
    handleFiles(dt.files);
  };

  const onChoose = (e) => {
    handleFiles(e.target.files);
  };

  return (
    <div>
      <div className="border-2 border-dashed border-slate-200 rounded-xl p-8 flex flex-col items-center">
        <div className="mb-4 text-slate-700 text-center">
          <h3 className="text-2xl font-semibold">Upload Your Book Files</h3>
          <p className="text-sm text-slate-500">
            PDF, DOCX, TXT, MD â€” up to 50MB
          </p>
        </div>

        <div
          onDrop={onDrop}
          onDragOver={(e) => e.preventDefault()}
          className="w-full py-12 flex items-center justify-center rounded-lg bg-gradient-to-br from-slate-50 to-white"
        >
          <div className="text-center">
            <input
              ref={fileRef}
              type="file"
              onChange={onChoose}
              className="hidden"
            />
            <button
              onClick={() => fileRef.current?.click()}
              className="px-6 py-3 bg-blue-600 text-white rounded-md shadow"
            >
              Upload a file
            </button>
            <div className="mt-4 text-sm text-slate-500">
              or drag and drop here
            </div>
          </div>
        </div>

        <div className="mt-6 w-full">
          {isUploading && (
            <div className="w-full bg-slate-100 rounded overflow-hidden">
              <div
                style={{ width: `${progress}%` }}
                className="h-2 bg-blue-600 transition-all"
              />
              <div className="text-sm text-slate-600 mt-2">
                Uploading: {progress}%
              </div>
            </div>
          )}

          <div className="mt-4">
            <h4 className="text-sm font-medium text-slate-700">Files</h4>
            <ul className="mt-2 space-y-2">
              {manuscriptFiles.map((f) => (
                <li
                  key={f.id}
                  className="flex items-center justify-between border rounded p-2"
                >
                  <div>
                    <div className="font-medium">{f.name}</div>
                    <div className="text-xs text-slate-500">
                      {f.status || 'ready'}
                    </div>
                  </div>
                  <div className="text-sm text-slate-500">
                    {Math.round((f.size || 0) / 1024)} KB
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </div>

      <div className="mt-6 flex justify-end">
        {/* Continue button is handled in WorkflowContainer */}
      </div>
    </div>
  );
};

export default UploadStep;
